class Solution:
    def canSplitArray(self, nums: List[int], m: int) -> bool:
        n = len(nums)
        if n == 1:
            return True

        # Check if all subarrays of length >= 2 have sum >= m
        for i in range(n - 1):
            if sum(nums[i:i+2]) < m:
                return False
        return True
